				message.includes("invalid")
			) {
				stage = "validation_error";
			} else if (message.includes("parse") || message.includes("parseable")) {
				stage = "parse_error";
			}

			failedAttempts.push({
				attempt,
				stage,
				errorMessage: boundedErrorMessage(message),
				rawOutput: {
					available: Boolean(raw),
					preview: raw ? safeTextPreview(raw, 320) : undefined,
				},
				command: command && isSafeCommand(command) ? command : undefined,
			});
		}
	}
	}

