			evidence?.classifierDiagnostics?.failedAttempts[0]?.rawOutput?.preview?.includes(
				"attempted raw snippet",
			),
		).toBe(false);
		expect(evidence?.classifierDiagnostics?.failedAttempts[1]?.rawOutput?.available).toBe(
			true,
		);
	} finally {
		client.close();
		database.cleanup();
	}
});

