function boundedErrorMessage(message: string, maxCharacters = 360): string {
	const trimmed = message.trim();
	if (trimmed.length <= maxCharacters) {
		return trimmed;
	}

	return `${trimmed.slice(0, maxCharacters - 1)}…`;
