			cwd: options.cwd,
			stdio: ["pipe", "pipe", "pipe"],
		});
		const stdoutChunks: Buffer[] = [];
		const stderrChunks: Buffer[] = [];
		let timedOut = false;
		let settled = false;
		let spawnError: string | null = null;
		let forceKillTimeout: NodeJS.Timeout | null = null;

		const timeout =
