test("intake sandbox runner writes classified prompt, schema, and codex proxy path", async () => {
	process.env.VERCEL_URL = "https://example.vercel.app";
	const { deps, commands, writeFiles } = createSandboxIntakeClassifierDeps();
	const result = await intakeClassifierSandbox.runIntakeClassifierInSandbox({
		prompt: "Classify issue",
		schemaFilePath: await (async () => {
			const tempDir = mkdtempSync(path.join(tmpdir(), "rhapsody-intake-schema-"));
			const schemaPath = path.join(tempDir, "schema.json");
			await writeFile(schemaPath, JSON.stringify({ type: "object" }), "utf8");
			return schemaPath;
		})(),
		dependencies: deps,
	});

	try {
		expect(result.rawOutputAvailable).toBe(true);
		expect(result.raw).toContain("\"decision\": \"buildable\"");
		expect(commands).toHaveLength(2);
		expect(commands[0]).toMatchObject({
			cmd: "codex",
			cwd: "/vercel/sandbox",
		});
		expect(commands[0].args).toContain("--output-schema");
		expect(commands[0].args).toContain("/vercel/sandbox/intake-classifier/schema.json");
		expect(commands[0].args).toContain("--output-last-message");
		expect(commands[0].args).toContain("/vercel/sandbox/intake-classifier/output.json");

		expect(writeFiles.some((file) => file.path.endsWith("auth.json"))).toBe(true);
		expect(writeFiles.some((file) => file.path.includes("prompt.txt"))).toBe(true);
		expect(writeFiles.some((file) => file.path.includes("schema.json"))).toBe(true);
	} finally {
		expect(deps.stopVercelSandbox).toHaveBeenCalledTimes(1);
	}
});

