	const callbackHost = new URL(args.callbackUrl).hostname;
	const headers = {
		"x-rhapsody-mediator-secret": args.mediatorSecret,
		...(args.vercelProtectionBypassSecret
			? { "x-vercel-protection-bypass": args.vercelProtectionBypassSecret }
			: {}),
	};

	return {
		allow: {
			[callbackHost]: [
