function runCommand(command, args, cwd) {
	return new Promise((resolve) => {
		const child = spawn(command, args, {
			stdio: ["ignore", "pipe", "pipe"],
			cwd,
		});
		let stdout = "";
		let stderr = "";
		let spawnError = null;

		child.stdout.on("data", (chunk) => {
			stdout += chunk.toString("utf8");
		});

		child.stderr.on("data", (chunk) => {
			stderr += chunk.toString("utf8");
		});

		child.on("error", (error) => {
			spawnError = error.message;
		});

		child.on("close", (code) => {
			resolve({
				command,
				args,
				exit_code: code,
				stdout: stdout.slice(0, OUTPUT_PREVIEW_LENGTH),
				stderr: stderr.slice(0, OUTPUT_PREVIEW_LENGTH),
				error: spawnError,
			});
		});
	});
}

async function readJsonPrSpec() {
	try {
		const rawPrSpec = await readFile(PR_SPEC_PATH, "utf8");
		const parsed = JSON.parse(rawPrSpec);

		if (
			typeof parsed !== "object" ||
			parsed === null ||
			typeof parsed.title !== "string" ||
			!parsed.title.trim() ||
			typeof parsed.body !== "string" ||
			!parsed.body.trim()
		) {
			return {
				ok: false,
				error:
					"PR spec was present but not a valid non-empty { title, body } object.",
			};
		}

		return { ok: true, value: parsed };
	} catch (error) {
		return {
			ok: false,
			error:
				error &&
				typeof error === "object" &&
				"code" in error &&
				error.code === "ENOENT"
					? "Could not find PR spec at " + PR_SPEC_PATH + "."
					: "PR spec must be readable JSON with non-empty title and body.",
		};
	}
}

async function sendTerminalCallback(payload) {
	const callbackUrl = requiredEnv("RHAPSODY_CALLBACK_URL");
	let lastResult = null;

	for (const delayMs of [0, 1_000, 3_000]) {
		if (delayMs > 0) {
			await sleep(delayMs);
		}

		try {
			const response = await fetch(callbackUrl, {
				method: "POST",
				headers: {
					"content-type": "application/json",
				},
				body: JSON.stringify(payload),
			});
			const text = await response.text();
			lastResult = {
				status: response.status,
				ok: response.ok,
				body: safeJson(text),
			};

			if (response.ok) {
				return lastResult;
			}
		} catch (error) {
			lastResult = {
				status: null,
				ok: false,
				body: error instanceof Error ? error.message : String(error),
			};
		}
	}

	return lastResult;
}

function sleep(ms) {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

function safeJson(text) {
	if (!text) {
		return null;
	}

	try {
		return JSON.parse(text);
	} catch {
		return text;
	}
}

