			"[redacted]",
		)
		.replace(/\bbearer\s+[\w-]+/gi, "bearer [redacted]");
	const normalized = redacted.replace(/\s+/g, " ").trim();
	if (normalized.length <= maxCharacters) {
		return normalized;
	}

	return `${normalized.slice(0, maxCharacters - 1)}…`;
