				input: {
					cmd?: string;
					args?: string[];
					argv?: string[];
					cwd?: string;
					timeoutMs?: number;
				} = {},
			) => {
				commandInvocation += 1;
				const commandArgs: string[] = input.args ?? input.argv ?? [];
				commands.push({
					cmd: input.cmd,
					args: commandArgs,
					serializedInput: JSON.stringify(input),
					cwd: input.cwd,
					stdout: "",
					exitCode: 0,
				});

				if (commandInvocation >= 2) {
					return {
						commandId: "cmd-cat",
						cwd: input.cwd ?? "/vercel/sandbox",
						startedAt: Date.now(),
						exitCode: 0,
						stdout: JSON.stringify({
