		cwd: metadata.command.cwd,
	});

	let stdout = "";
	let stderr = "";
	let spawnError = null;
	let timedOut = false;

	child.stdout.on("data", (chunk) => {
		stdout += chunk.toString("utf8");
	});

	child.stderr.on("data", (chunk) => {
